__d(function(g,r,i,a,m,e,d){m.exports="# Bienvenue chez moi!\n\nI'm a passionate coder, freelance developer, and software consultant, specializing in distributed **P2P** systems, write-once-run-anywhere cross-platform solutions, and offline-first local-first edge computing.\n\nI'm a firm believer in **Open-Source**, and I contribute to the community whenever I can.\n\nI've been coding since 2014 and most notably I was part of the team that built mobile **P2P** messaging and video call app [Keet](https://keet.io/) while I was working with [Holepunch \ud83d\udd73\ufe0f\ud83e\udd4a](https://holepunch.to/).\n\nMy skills are rentable, [drop me an line](mailto:tomas@tomasrav.me) and we will work out the details.\n"},1156,[]);
__d(function(g,r,i,a,m,e,d){m.exports="The server-client model is outdated and fragile. Now that consumer and edge devices can perform expensive computations locally the server is just a centralized point of failure, and frankly, redundant The future is here and the future is **Peer-to-Peer**!\n"},1157,[]);
