     // Remove all files from the out dir.\n      new CleanWebpackPlugin({\n        cleanOnceBeforeBuildPatterns: itemsToClean,\n        verbose: !!verbose,\n      }),\n      // Copy assets\n      new CopyWebpackPlugin(\n        [\n          ...copyTargets,\n          { from: { glob: \"**/*.jpg\", dot: false } },\n          { from: { glob: \"**/*.png\", dot: false } },\n        ],\n        copyIgnore,\n      ),\n      new nsWebpack.GenerateNativeScriptEntryPointsPlugin(\"bundle\"),\n      // For instructions on how to set up workers with webpack\n      // check out https://github.com/nativescript/worker-loader\n      new NativeScriptWorkerPlugin(),\n      ngCompilerPlugin,\n      // Does IPC communication with the {N} CLI to notify events when running in watch mode.\n      new nsWebpack.WatchStateLoggerPlugin(),\n    ],\n    stats: {\n      warningsFilter: [/critical dependency:/i],\n    },\n  }\n\n  if (report) {\n    // Generate report files for bundles content\n    config.plugins.push(\n      new BundleAnalyzerPlugin({\n        analyzerMode: \"static\",\n        openAnalyzer: false,\n        generateStatsFile: true,\n        reportFilename: resolve(projectRoot, \"report\", `report.html`),\n        statsFilename: resolve(projectRoot, \"report\", `stats.json`),\n      }),\n    )\n  }\n\n  if (snapshot) {\n    config.plugins.push(\n      new nsWebpack.NativeScriptSnapshotPlugin({\n        chunk: \"vendor\",\n        angular: true,\n        requireModules: [\n          \"reflect-metadata\",\n          \"@angular/platform-browser\",\n          \"@angular/core\",\n          \"@angular/common\",\n          \"@angular/router\",\n          \"@nativescript/angular\",\n        ],\n        projectRoot,\n        webpackConfig: config,\n        snapshotInDocker,\n        skipSnapshotTools,\n        useLibs,\n      }),\n    )\n  }\n\n  if (!production && hmr) {\n    config.plugins.push(new webpack.HotModuleReplacementPlugin())\n  }\n\n  return config\n}\n```\n"},1167,[]);
__d(function(g,r,i,a,m,e,d){const t=Object.defineProperties({},{"./en/kitchen/posts/bell-pepper-soup.md":{enumerable:!0,get:()=>r(d[0])},"./en/kitchen/posts/cacao-quality.md":{enumerable:!0,get:()=>r(d[1])},"./en/kitchen/posts/cannelloni.md":{enumerable:!0,get:()=>r(d[2])},"./en/kitchen/posts/cinnamon-rolls.md":{enumerable:!0,get:()=>r(d[3])},"./en/kitchen/posts/cold-borscht.md":{enumerable:!0,get:()=>r(d[4])},"./en/kitchen/posts/deviled-eggs.md":{enumerable:!0,get:()=>r(d[5])},"./en/kitchen/posts/japanese-style-rice.md":{enumerable:!0,get:()=>r(d[6])},"./en/kitchen/posts/kuciukai.md":{enumerable:!0,get:()=>r(d[7])},"./en/kitchen/posts/meringues.md":{enumerable:!0,get:()=>r(d[8])},"./en/kitchen/posts/pirozhki.md":{enumerable:!0,get:()=>r(d[9])},"./en/kitchen/posts/tinginys.md":{enumerable:!0,get:()=>r(d[10])},"./lt/kitchen/posts/bell-pepper-soup.md":{enumerable:!0,get:()=>r(d[11])},"./lt/kitchen/posts/cacao-quality.md":{enumerable:!0,get:()=>r(d[12])},"./lt/kitchen/posts/cannelloni.md":{enumerable:!0,get:()=>r(d[13])},"./lt/kitchen/posts/cinnamon-rolls.md":{enumerable:!0,get:()=>r(d[14])},"./lt/kitchen/posts/cold-borscht.md":{enumerable:!0,get:()=>r(d[15])},"./lt/kitchen/posts/deviled-eggs.md":{enumerable:!0,get:()=>r(d[16])},"./lt/kitchen/posts/japanese-style-rice.md":{enumerable:!0,get:()=>r(d[17])},"./lt/kitchen/posts/kuciukai.md":{enumerable:!0,get:()=>r(d[18])},"./lt/kitchen/posts/meringues.md":{enumerable:!0,get:()=>r(d[19])},"./lt/kitchen/posts/pirozhki.md":{enumerable:!0,get:()=>r(d[20])},"./lt/kitchen/posts/tinginys.md":{enumerable:!0,get:()=>r(d[21])}});function n(n){return t[n]}n.keys=function(){return Object.keys(t)},n.resolve=function(t){throw new Error('Unimplemented Metro module context functionality')},m.exports=n},1168,[1169,1170,1171,1172,1173,1174,1175,1176,1177,1178,1179,1180,1181,1182,1183,1184,1185,1186,1187,1188,1189,1190]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"Bell Pepper Soup\"\nslug: bell-pepper-soup\nauthor: Tomas Ravinskas\npublished: 2024-07-26T07:34:13+0300\n---\n\n| Amount   | Ingredient            |\n| -------- | --------------------- |\n| 1        | Red bell pepper       |\n| 1        | Yellow bell pepper    |\n| 1        | Green bell pepper     |\n| 3        | Carrots               |\n| 2 cans   | Butter beans          |\n| 500 g    | Lean pork             |\n| 2 cubes  | Dry mushroom bouillon |\n| 3 cloves | Garlic                |\n| To taste | Black pepper          |\n| A pinch  | Chilli powder         |\n| A pinch  | Salt                  |\n| 1-1.5 l  | Hot water             |\n\n---\n\nCut the pork into bite sized cubes, season with crushed garlic, black pepper, chilli powder, and salt. Let it rest for a bit.\n\nSlice the carrots, cut bell peppers into thin strips, wash the beans. In large pot over high heat fry the pork. When pork slightly browns, add the carrots. Once carrots are about cooked, add the bell peppers, stir well, and fry until they soften. Melt the bouillon in hot water and pour over the pork and vegetables. Once the water boils, add the beans, lightly stir, let it simmer for 15 minutes.\n"},1169,[]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"Cacao Quality\"\nslug: cacao-quality\nauthor: Tomas Ravinskas\npublished: 2020-08-01T07:44:36+0300\nedited: 2024-07-24T05:17:13+0300\nsource: https://food52.com/blog/9521-how-to-identify-good-cocoa-powder-and-not-so-good\n---\n\nHave you ever baked a chocolate pie that didn't quite taste like chocolate?\n\nThe issue is the cacao. Most cacao, especially cheap brands, is around 12% fat, which is quite low. This cacao tastes like sawdust.\n\nInstead, when buying cacao, make sure fat content is at least 22%. This usually not advertised, but you can look at nutritional label - look for cacao with 1 gram (instead of 0.5 gram) of fat per 5 to 6 gram serving, or at least 22 gram fat content per 100 gram.\n\nThis will greatly improved the flavor of pies, cookies, and yes, hot chocolate too.\n"},1170,[]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"Cannelloni\"\nslug: cannelloni\nauthor: Tomas Ravinskas\npublished: 2020-08-01T07:36:14+0300\nedited: 2024-07-24T05:36:13+0300\n---\n\n### For the filling\n\n| Amount   | Ingredient   |\n| -------- | ------------ |\n| 500 g    | ground pork  |\n| 200 g    | spinach      |\n| 1 tbsp   | butter       |\n| 1        | egg          |\n| 3 cloves | garlic       |\n| A pinch  | salt         |\n| A pinch  | black pepper |\n| A pinch  | basil        |\n| A pinch  | oregano      |\n\n### For the Mornay sauce\n\n| Amount | Ingredient                                |\n| ------ | ----------------------------------------- |\n| 2 tbsp | butter                                    |\n| 1 tbsp | flour                                     |\n| 400 ml | milk                                      |\n| 100 g  | hard cheese of your choice                |\n| 100 g  | another cheese of your choice (not moldy) |\n\n### For the tomato sauce\n\n| Amount | Ingredient                            |\n| ------ | ------------------------------------- |\n| 200 ml | any tomato sauce (store bought works) |\n\nYou'll also need a box of cannelloni pasta, obviously.\n\n---\n\nFirst, let's make the Mornay sauce. In deep pan, on low heat, melt the butter. Throw in the flour and mix well until golden. Without stopping the mixing, slowly pour in the milk, little bit at a time. Once the milk begins to thicken start adding the cheeses, a handful at a time. Don't stop the mixing until all the cheese is incorporated into the sauce.\n\nNow let's make the filling. Melt the butter in a pan over low heat. Toss in the spinach. Once the spinach shrinks, drain the liquid. In a large bowl mix the spinach and the remaining ingredients. Stuff the cannelloni.\n\nIn a large baking dish pour in the tomato sauce. Arrange the cannelloni and cover with Mornay sauce. Bake for 40 minutes in 180\xb0C.\n"},1171,[]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"Cinnamon Rolls\"\nslug: cinnamon-rolls\nauthor: Tomas Ravinskas\npublished: 2020-08-01T05:17:00+0300\nedited: 2024-07-24T06:34:13+0300\nsource: https://www.ambitiouskitchen.com/best-cinnamon-rolls/\n---\n\n### For the dough\n\n| Amount | Ingredient                   |\n| ------ | ---------------------------- |\n| 180 ml | warm milk                    |\n| 30 g   | fresh yeast                  |\n| 50 g   | granulated sugar             |\n| 1      | egg at room temperature      |\n| 1      | egg yolk at room temperature |\n| 60 g   | melted butter                |\n| 360 g  | all purpose flour            |\n| 1 tsp  | salt                         |\n\n### For the filling\n\n| Amount | Ingredient      |\n| ------ | --------------- |\n| 120 g  | brown sugar     |\n| 2 tbsp | ground cinnamon |\n| 60 g   | softened butter |\n\n---\n\nPut the yeast and 1 teaspoon of sugar in warm milk and mix until yeast melts, then let it rest for about 10 minutes.\nWhisk the egg and the egg yolk with remaining sugar. Mix the milk, the egg mass, and the melted butter. In separate bowl sift the flour and mix in the salt. Then mix everything together and knead well for a few minutes.\n\nCover the dough with a damp cotton cloth and let it rise. How long depends on temperature and humidity. On a typical Lithuanian summer 60 minutes is more than enough. It may take 90 minutes or more during cold season.\n\nWhile the dough is rising, pour the filling ingredients into a bowl and use hand mixer to whisk it together. A blender also works if you have one.\n\nRoll the dough on a floured surface into roughly square shape, around 1 cm thick. Use a spoon, or a butter knife, to spread the filling evenly, leaving a couple centimeters from the edges.\n\nRoll up the dough and use dental floss to cut it into about 3 cm slices. Place the slices onto baking tray covered with a baking sheet leaving a few centimeters space between them.\n\nBake until golden, but still soft in the middle, around 40 minutes.\n"},1172,[]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"Cold Borscht\"\nslug: cold-borscht\nauthor: Tomas Ravinskas\npublished: 2020-08-01T09:37:01+0300\nedited: 2024-07-24T07:11:13+0300\n---\n\n| Amount   | Ingredient                                            |\n| -------- | ----------------------------------------------------- |\n| 0.5 l    | pickled beetroots (pickled in apple juice works best) |\n| 1 l      | kefir (buttermilk works in a pinch)                   |\n| 3-4      | cucumbers                                             |\n| To taste | fresh or salted dill                                  |\n| To taste | spring onion                                          |\n| 3-4      | hard boiled eggs                                      |\n| A pinch  | salt                                                  |\n\n> Spring onion and hard boiled eggs are optional\n\n---\n\nChop the cucumbers into bite sized pieces. Finely chop the dill and the spring onion. You can either chop the hard boiled eggs, or slice them in half and place them directly in the plate when serving the soup. Mix everything in a large pot. If the soup seems too thick, use boiled or filtered water to dilute it.\nRefrigerate for a few hours, the soup will taste much better than freshly made.\nServe with hot potatoes.\n\n---\n\nFew things to note:\n\n- Traditionally, boiled and grated beetroots were used. However pickled beetroots have more tang, which is very welcome here.\n- Egg and spring onion are popular additions, to the point where most Lithuanians consider them essential. Personally, I'm not a fan.\n- According to Wikipedia radish can also be added. Never seen this in practice tho.\n- I've seen people put the hot potatoes straight into the soup. That's silly, it ruins the temperature balance.\n"},1173,[]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"Deviled Eggs\"\nslug: deviled-eggs\nauthor: Tomas Ravinskas\npublished: 2020-08-01T06:46:12+0300\nedited: 2024-07-24T08:14:13+0300\n---\n\n| Amount   | Ingredient     |\n| -------- | -------------- |\n| 6        | eggs           |\n| 2 tbsp   | mayo           |\n| 1 tsp    | mustard        |\n| 1 tsp    | smoked paprika |\n| To taste | black pepper   |\n\n---\n\nGently put the eggs into the boiling water and boil for 7 minutes. Strain the eggs and put them into cold water. Leave them to cool for another 15 minutes. Peel the eggs, cut them in half length-wise, and take out the yolks.\n\nIn a bowl mix the egg yolks with mayo, mustard, paprika, and pepper. Scoop up the mass with a teaspoon and put it back into the egg whites.\n"},1174,[]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"Japanese style rice in a frying pan\"\nslug: japanese-style-rice\nauthor: Tomas Ravinskas\npublished: 2020-08-01T06:48:06+0300\nedited: 2024-07-24T08:31:13+0300\nsource: http://justhungry.com/how-cook-perfect-rice-in-frying-pan-fast-and-foolproof\n---\n\nJapanese style medium-grain white rice (steamed medium grain white rice seems to work just fine) (see [Looking at rice](http://www.justhungry.com/2007/01/looking_at_rice.html))\nA frying pan with a non-stick surface. I used a 28 cm / 11 inch diameter model. I recommend a similar size for making 1 to 2 cups of rice.\nA tight fitting lid for the frying pan. The lid does need to fit well so that excess steam gets trapped. A glass one is nice since it lets you see your rice's progress without opening the lid.\nFollowing the method described in my basic rice how-to ([Japanese rice basics](http://justhungry.com/2003/11/japanese_basics_1.html)), rinse the rice and drain it well. (Rinsing does make a difference in taste! You just need to do it a few times.) Put the drained rice plus 1.1 times the amount of water by volume in the frying pan. So, if you have 1 cup of rice, use 1 cup and a bit of water. For 2 cups of rice, use 2.2 cups (about 2 and 1/4) water. I don't recommend doing more than 2 cups at a time in this size frying pan.\n\nAt this point, ideally you'll let the rice soak a bit (about half an hour) for plumper grains, but you can skip the soaking if you're in a big hurry.\n\nPut the frying pan on the stove top over high heat with the lid on. Bring to a boil - the water will bubble aggressively, like so.\n\nGive the rice a good stir up from the bottom with a spoon or spatula.\n\nReplace the lid tightly. Lower the heat immediately to low.\n\nIf you're using an electric range, the heat will not respond instantly so you'll have high heat for a couple of minutes. Take the frying pan off the hot burner for a couple of minutes until the burner has had a chance to cool down to the low level.\n\nLet the rice cook on the low setting. You'll see the water get absorbed rapidly and big, starchy bubbles on the surface. This only takes about 5 minutes so be sure you're hovering near the pan with an eye on it! (I do other dinner-prep stuff while the rice is steaming.)\n\nOnce the bubbles have subsided, you'll see the surface of the rice with nice, even steam holes all over it. As soon this happens, turn the heat up to high for a minute or two, then turn the heat off. If you're using an electric range, take the pan off the hot burner and put it somewhere else (like on top of an unused burner).\n\nLet the pan rest with the lid on for a minimum of 10 minutes. This is very important, otherwise you may end up with a little hard center in your rice grains. Al dente is good for pasta, not for rice! (At least, it's not good for Japanese style rice. Other rices, I don't think so either.)\n"},1175,[]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"K\u016b\u010diukai\"\nslug: kuciukai\nauthor: Tomas Ravinskas\npublished: 2020-12-30T20:40:19+0300\nedited: 2024-07-24T09:48:13+0300\n---\n\n| Amount | Ingredient        |\n| ------ | ----------------- |\n| 500 g  | all purpose flour |\n| 3      | eggs              |\n| 250 ml | milk              |\n| 30 g   | fresh yeast       |\n| 100 g  | sugar             |\n| 1 tsp  | salt              |\n| 2 tbsp | vegetable oil     |\n| 50 g   | poppy seeds       |\n\n---\n\nWarm up the milk (60s in the microwave on high setting), put in a teaspoon of sugar and the yeast. Mix until yeast melts, then let the yeast activate, about 10 minutes. In a large, shallow bowl mix the milk, the rest of sugar, oil, eggs, and poppy seeds. Mix the flour with the salt and sift it into the egg mass. Knead, adding flour as needed, until the dough does not stick to your hands. Cover the dough with a damp cotton cloth and let it rise for about 60 minutes.\nCut off a piece of dough and roll it into a string about 1 cm thick. Cut into 1 cm thick pieces. Spread a baking sheet onto a baking tray and put the pieces on it. Bake on both sides until golden.\n"},1176,[]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"Meringues\"\nslug: meringues\nauthor: Tomas Ravinskas\npublished: 2020-08-01T07:59:03+0300\nedited: 2024-07-24T08:35:13+0300\nsource: \"Old recipe book my sister found in Germany\"\n---\n\n| Amount | Ingredient       |\n| ------ | ---------------- |\n| 1      | large egg white  |\n| 80 g   | granulated sugar |\n| A dash | lemon juice      |\n\n---\n\nWhisk the egg white with the sugar and the lemon juice until it forms soft peaks (it's never going to form stiff peaks because of all the sugar). Scoop ip the mass with a teaspoon and place on baking sheet covered tray (or better yet, fill up confectioners syringe with the mass and make pretty little puffs). Bake for 25 minutes at 180\xb0C.\n\nOne portion makes about half full-sized baking tray.\n"},1177,[]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"Pirozhki\"\nslug: pirozhki\nauthor: Tomas Ravinskas\npublished: 2020-08-01T10:17:37+0300\nedited: 2024-07-24T09:09:13+0300\n---\n\n### For the dough\n\n| Amount | Ingredient        |\n| ------ | ----------------- |\n| 100 ml | milk              |\n| 30 g   | fresh yeast       |\n| 1 tsp  | sugar             |\n| 3      | large eggs        |\n| 500 g  | all purpose flour |\n| 1 tsp  | salt              |\n\n### For the filling\n\n| Amount | Ingredient             |\n| ------ | ---------------------- |\n| 500 g  | meat (chicken or pork) |\n| 200 g  | grated hard cheese     |\n| 1 cube | dry mushroom bouillon  |\n\n---\n\nPut the milk in the microwave on high setting for 60 seconds. Pour the sugar and the yeast into the warm milk and mix until yeast melts (sugar helps the yeast activate, there will be no sweetness in the dough). Let it rest for about 10 minutes until the yeast activates. In a large, shallow bowl mix the milk and the eggs. Mix the flour with the salt and sift into the milk and egg mixture. Knead until the dough stops sticking to your hands. Cover with a damp cotton cloth and leave the dough to rise for about 60 minutes.\n\nWhile the dough is rising, make the filling. Put the meat in cold water and bring to a boil. Strain the meat, pour in clean water, and add the bouillon. Boil for 30 minutes or until the meat is cooked. Let the meat cool, then mince it and add the cheese. Add a few spoons of the meat/mushroom stock until a thick paste forms.\n\nCut off a piece of dough and roll it thinly. Use a glass to cut out circles from the rolled dough. Put a teaspoon of filling paste in the middle of a circle and fold it. Fold the edges so it forms a neat little dumpling. Rinse and repeat.\n\nPour 1 l of vegetable or similar oil into a frying pan on medium heat. Once the oil is hot, put in a few pirozhki and fry until golden. When one side turns golden, flip them over, and again, fry until golden.\n\nSpread a couple paper towels in a large bowl and fish out the pirozhki into it. The paper towel will absorb excess oil, preventing pirozhki from getting soggy.\n"},1178,[]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"Sloth Pie (Crumb Pie)\"\nslug: tinginys\nauthor: Tomas Ravinskas\npublished: 2020-08-01T07:59:23+0300\nedited: 2024-07-24T07:53:13+0300\n---\n\n| Amount        | Ingredient                                     |\n| ------------- | ---------------------------------------------- |\n| 900 g         | plain biscuits (I use either Selga or Leibniz) |\n| 1 can (400 g) | sweetened condensed milk                       |\n| 200 g         | butter                                         |\n| 250 g         | margarine                                      |\n| 3 tbsp        | granulated sugar                               |\n| 5 tbsp        | cacao                                          |\n\n---\n\nCrumble the biscuits to about 1 cm sized pieces. Melt the butter and the margarine in a pot over low heat. Stir in the sugar. Keep stirring 'til the sugar completely melts. Still stirring, pour in the condensed milk. Keep stirring 'til it's completely incorporated and uniform. Turn off the heat and let it cool around 10-15 minutes.\n\nStir in cacao and pour the mass over the biscuit crumbs. Mix well, pour it into deep, narrow, baking tray and put in the fridge overnight.\n\n---\n\nI know a lot of people don't like margarine, but it really works well here. You can use all butter (replacing margarine with equal amount of butter), but the end result will be much tougher to bite.\n"},1179,[]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"Paprik\u0173 Sriuba\"\nslug: bell-pepper-soup\nauthor: Tomas Ravinskas\npublished: 2024-07-26T07:34:13+0300\n---\n\n| Kiekis      | Ingredientas        |\n| ----------- | ------------------- |\n| 1           | Raudonoji paprika   |\n| 1           | Geltonoji paprika   |\n| 1           | \u017dalioji paprika     |\n| 3           | Morkos              |\n| 2 skardin\u0117s | Sviestini\u0173 pupeli\u0173  |\n| 500 g       | Liesos kiaulienos   |\n| 2 kubeliai  | Sauso gryb\u0173 buljono |\n| 3 skiltel\u0117s | \u010cesnako             |\n| Pagal skon\u012f | Juod\u0173j\u0173 pipir\u0173      |\n| \u017diupsnelio  | Malt\u0173 \u010dili pipir\u0173   |\n| \u017diupsnelio  | Druskos             |\n| 1-1.5 l     | Kar\u0161to vandens      |\n\n---\n\nSupjaustykite kiaulien\u0105 kasnio dyd\u017eio gabal\u0117liais, suberkite trint\u0105 \u010desnak\u0105, juoduosius pipirus, \u010dili, ir drusk\u0105. I\u0161mai\u0161ykite ir palikite marinuotis.\n\nSupjaustykite riekel\u0117mis morkas, paprikas - \u0161iaudeliais, nuplaukite pupeles. Dideliame puode, and auk\u0161tos liepsnos, i\u0161kepkite kiaulien\u0105. Kai kiauliena prad\u0117s ruduoti, suberkite morkas. Kai morkos bus daugma\u017e i\u0161kepusios, sud\u0117kite paprikas, pamai\u0161ykite, ir kepkite kol paprikos sumink\u0161t\u0117s. Kar\u0161tame vandenyje i\u0161tirpinkite buljon\u0105 ir supilkite and m\u0117sos ir dar\u017eovi\u0173. Kai vanduo u\u017evirs, suberkite pupeles, lengvai pamai\u0161ykite, ir pavirkite dar 15 minu\u010di\u0173.\n"},1180,[]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"Kakavos Kokyb\u0117\"\nslug: cacao-quality\nauthor: Tomas Ravinskas\npublished: 2020-08-01T07:44:36+0300\nedited: 2024-07-24T05:17:13+0300\nsource: https://food52.com/blog/9521-how-to-identify-good-cocoa-powder-and-not-so-good\n---\n\nAr kada nors teko i\u0161kepti \u0161okoladin\u012f pyrag\u0105, kuris visai neprimin\u0117 \u0161okolado?\n\nProblema grei\u010diausiai kakavoje. Did\u017eioji dalis kakavos, ypa\u010d pig\u016bs prek\u0117s \u017eenklai, turi apie 12% riebal\u0173, kas yra labai ma\u017eai. Tokia kakava labiau primena pjuvenas.\n\nGeriau, pirkdami kakav\u0105, \u012fsitikinkite, kad joje riebal\u0173 nema\u017eiau nei 22%. \u0160ios informacijos da\u017eniausiai nereklamuoja, ta\u010diau j\u0105 galite su\u017einoti pa\u017ei\u016br\u0117j\u0119 \u012f maistingumo deklaracij\u0105 - ie\u0161kokite kakavos su 1 gramu (vietoj 0.5 gram\u0173) riebal\u0173 5-6 gram\u0173 porcijoje, arba bent 22 gramais riebal\u0173 100 gram\u0173.\n\nTokia kakava smarkiai pagerins j\u016bs\u0173 kepini\u0173 skon\u012f, ir taip pat puikiai tinka kar\u0161tam \u0161okoladui.\n"},1181,[]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"Cannelloni\"\nslug: cannelloni\nauthor: Tomas Ravinskas\npublished: 2020-08-01T07:36:14+0300\nedited: 2024-07-24T05:36:13+0300\n---\n\n### \u012edarui\n\n| Kiekis      | Ingredientas     |\n| ----------- | ---------------- |\n| 500 g       | kiaulienos far\u0161o |\n| 200 g       | \u0161pinat\u0173          |\n| 1 \u0161auk\u0161to   | sviesto          |\n| 1           | kiau\u0161inio        |\n| 3 skilteli\u0173 | \u010desnako          |\n| \u017diupsnelio  | druskos          |\n| \u017diupsnelio  | juod\u0173j\u0173 pipir\u0173   |\n| \u017diupsnelio  | baziliko         |\n| \u017diupsnelio  | raudon\u0117lio       |\n\n### Mornay pada\u017eui\n\n| Kiekis    | Ingredientas                           |\n| --------- | -------------------------------------- |\n| 2 \u0161auk\u0161t\u0173 | sviesto                                |\n| 1 \u0161auk\u0161t\u0173 | milt\u0173                                  |\n| 400 ml    | pieno                                  |\n| 100 g     | kietojo s\u016brio                          |\n| 100 g     | j\u016bs\u0173 m\u0117giamo s\u016brio (i\u0161skyrus pel\u0117sin\u012f) |\n\n### Pomidor\u0173 pada\u017eui\n\n| Kiekis | Ingredientas                                     |\n| ------ | ------------------------------------------------ |\n| 200 ml | bet kokio pomidor\u0173 pada\u017eo (i\u0161 parduotuv\u0117s tinka) |\n\nJums taip pat reik\u0117s d\u0117\u017eut\u0117s cannelloni makaron\u0173.\n\n---\n\nPirmiausia paruo\u0161kime Mornay pada\u017e\u0105. Gilioje keptuv\u0117je, and \u017eemos liepsnos, i\u0161tirpdykite sviest\u0105. Suberkite miltus, i\u0161mai\u0161ykite, ir pakepinkite kol miltai pagels. Toliau mai\u0161ydami po truput\u012f supilkite pien\u0105. Kai pienas prad\u0117s tir\u0161t\u0117ti po truput\u012f suberkite s\u016brius. Mai\u0161ykite kol s\u016bris visi\u0161kai i\u0161tirps ir pada\u017eas bus vientisas.\n\nDabar paruo\u0161kime \u012fdar\u0105. Keptuv\u0117je and \u017eemos liepsnos i\u0161tirpinkite sviest\u0105. Sud\u0117kite \u0161pinatus. Kai \u0161pinatai susitrauks, nusunkite skyst\u012f. Dubenyje sumai\u0161ykite \u0161pinatus ir likusius ingredientus. Dabar galite kim\u0161ti cannelloni.\n\nPla\u010dioje ir gilioje kepimo formoje supilkite ir paskleiskite pomidor\u0173 pada\u017e\u0105. I\u0161d\u0117liokite cannelloni ir u\u017epilkite Mornay pada\u017eu. Kepkite 40 minu\u010di\u0173 180\xb0C kar\u0161tyje.\n"},1182,[]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"Bandel\u0117s su Cinamonu\"\nslug: cinnamon-rolls\nauthor: Tomas Ravinskas\npublished: 2020-08-01T05:17:00+0300\nedited: 2024-07-24T06:34:13+0300\nsource: https://www.ambitiouskitchen.com/best-cinnamon-rolls/\n---\n\n### Te\u0161lai\n\n| Kiekis   | Ingredientas                            |\n| -------- | --------------------------------------- |\n| 180 ml   | \u0161ilto pieno                             |\n| 30 g     | \u0161vie\u017ei\u0173 mieli\u0173                          |\n| 50 g     | baltojo cukraus                         |\n| 1        | kiau\u0161inio, kambario temperat\u016bros        |\n| 1        | kiau\u0161inio trynio, kambario temperat\u016bros |\n| 60 g     | tirpdyto sviesto                        |\n| 360 g    | universali\u0173 milt\u0173                       |\n| \u017diupsnio | druskos                                 |\n\n### \u012edarui\n\n| Kiekis    | Ingredientas                            |\n| --------- | --------------------------------------- |\n| 120 g     | rudojo cukraus                          |\n| 2 \u0161auk\u0161t\u0173 | malto cinamono                          |\n| 60 g      | mink\u0161to sviesto (kambario temperat\u016bros) |\n\n---\n\nSud\u0117kite mieles ir 1 arbatin\u012f \u0161auk\u0161tel\u012f cukraus \u012f \u0161ilt\u0105 pien\u0105. Mai\u0161ykite kol miel\u0117s i\u0161tirps, tada palikite 10 minu\u010di\u0173.\nI\u0161plakite kiau\u0161in\u012f ir kiau\u0161inio tryn\u012f su likusiu cukrumi. Sumai\u0161ykite pien\u0105, kiau\u0161ini\u0173 mas\u0119, ir tirpint\u0105 sviest\u0105. Kitame dubenyje persijokite miltu ir \u012fmai\u0161ykite drusk\u0105. Tuomet visk\u0105 sumai\u0161ykite ir minkykite kelias minutes.\n\nU\u017edenkite te\u0161l\u0105 dr\u0117gnu medvilniniu audiniu ir leiskite jai pakilti, Kiek tai u\u017etruks priklausys nuo temperat\u016bros ir dr\u0117gm\u0117s. Lietuvi\u0161k\u0105 vasar\u0105 60 minu\u010di\u0173 bus net per daug. Ta\u010diau prie v\u0117sesni\u0173 or\u0173 tai gali trukti 90 minu\u010di\u0173, ar daugiau.\n\nKol te\u0161la kyla, suberkite \u012fdaro ingredientus \u012f duben\u012f ir i\u0161plakite rankiniu mikseriu. Blenderis taip pat tinka, jei j\u012f turite.\n\nI\u0161ko\u010diokite te\u0161l\u0105 and miltais pabarstyto pavir\u0161iaus, stengdamiesi suformuoti sta\u010diakamp\u012f, ma\u017edaug 1 cm storio. Naudodami \u0161auk\u0161t\u0105, ar sviestin\u012f peil\u012f, tolygiai paskirstykite \u012fdar\u0105, palikdami por\u0105 centimetr\u0173 nuo kra\u0161t\u0173.\n\nSuvyniokite te\u0161l\u0105 ir naudodami dant\u0173 si\u016bl\u0105 supjaustykite \u012f ma\u017edaug 3 cm storio riekeles. I\u0161d\u0117liokite riekeles \u012f kepimo skard\u0105 padengt\u0105 kepimo popieriumi, i\u0161laikydami keli\u0173 centimetr\u0173 tarpus tarp j\u0173.\n\nKepkite kol pagels, bet liks mink\u0161tos per viduriuk\u0105, apie 40 minu\u010di\u0173.\n"},1183,[]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"\u0160altibar\u0161\u010diai\"\nslug: cold-borscht\nauthor: Tomas Ravinskas\npublished: 2020-08-01T09:37:01+0300\nedited: 2024-07-24T07:11:13+0300\n---\n\n| Kiekis      | Ingredientas                                       |\n| ----------- | -------------------------------------------------- |\n| 0.5 l       | konservuot\u0173 burok\u0117li\u0173 (geriausiai obuoli\u0173 sultyse) |\n| 1 l         | kefyro (i\u0161 b\u0117dos - pasuk\u0173)                         |\n| 3-4         | agurk\u0173                                             |\n| Pagal skon\u012f | \u0161vie\u017ei\u0173 arba s\u016bdyt\u0173 krap\u0173                          |\n| Pagal skon\u012f | svog\u016bn\u0173 lai\u0161k\u0173                                     |\n| 3-4         | kietai virt\u0173 kiau\u0161ini\u0173                             |\n| \u017diupsnio    | druskos                                            |\n\n> Svog\u016bn\u0173 lai\u0161kai ir kietai virti kiau\u0161iniai **n\u0117ra b\u016btini**\n\nSupjaustykite agurkus kasnio dyd\u017eio gabal\u0117liais. Smulkiai supjaustykite krapus ir svog\u016bn\u0173 lai\u0161kus. Kiau\u0161inius galite arba supjaustyti kubeliais, arba pjauti per pus\u0119 ir d\u0117ti tiesiai \u012f l\u0117k\u0161t\u0119 kai tiekiate sriub\u0105. Visk\u0105 sumai\u0161ykite dideliame puode. Jei sriuba tir\u0161toka, atskieskite virintu arba filtruotu vandeniu.\nD\u0117kite puod\u0105 \u012f \u0161aldytuv\u0105 kelioms valandoms. Sriuba bus daug skanesn\u0117 nei \u0161vie\u017eiai paruo\u0161ta.\nTiekite su kar\u0161tomis bulv\u0117mis.\n\n---\n\nKeli dalykai, kuriuos verta pamin\u0117ti:\n\n- Tradici\u0161kai, buvo naudojami virti ir tarkuoti burok\u0117liai. Ta\u010diau konservuoti burok\u0117liai turi daugiau r\u016bg\u0161tel\u0117s, kas \u017eenkliai pagerina sriubos skon\u012f.\n- Kiau\u0161iniai ir svog\u016bn\u0173 lai\u0161kai yra populiar\u016bs priedai, dauguma Lietuvi\u0173 juos laiko neatskiriama \u0161altibar\u0161\u010di\u0173 dalimi. Bet a\u0161 j\u0173 nem\u0117gstu, bent jau ne \u0161altibar\u0161\u010diuose.\n- Pasak Vikipedijos taip pat galima d\u0117ti ridik\u0173. To dar niekur nema\u010diau.\n- Kai kurie \u017emon\u0117s kar\u0161tas bulves sudeda tiesiai \u012f sriub\u0105. Tai kvaila, sugadina temperat\u016bros balans\u0105.\n"},1184,[]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"Far\u0161iruoti Kiau\u0161iniai (Briti\u0161ku Stiliumi)\"\nslug: deviled-eggs\nauthor: Tomas Ravinskas\npublished: 2020-08-01T06:46:12+0300\nedited: 2024-07-24T08:14:13+0300\n---\n\n| Kiekis       | Ingredientas     |\n| ------------ | ---------------- |\n| 6            | kiau\u0161ini\u0173        |\n| 2 \u0161auk\u0161t\u0173    | majonezo         |\n| 1 \u0161auk\u0161telio | garsty\u010di\u0173        |\n| 1 \u0161auk\u0161telio | r\u016bkytos paprikos |\n| Pagal skon\u012f  | juod\u0173j\u0173 pipir\u0173   |\n\n---\n\n\u0160velniai sud\u0117kite kiau\u0161inius \u012f verdant\u012f vanden\u012f ir virkite 7 minutes. Nuko\u0161kite kiau\u0161inius ir sud\u0117kite \u012f \u0161alt\u0105 vanden\u012f. Leiskite jiems prav\u0117sti dar 15 minu\u010di\u0173. Nulupkite kiau\u0161inius, perpjaukite i\u0161ilgai, ir i\u0161imkite trynius.\n\nDubenyje sumai\u0161ykite kiau\u0161ini\u0173 trynius su majonezu, garsty\u010diomis, paprika, ir pipirais. Su arbatiniu \u0161auk\u0161teliu semkite \u0161i\u0105 mas\u0119 ir d\u0117kite atgal \u012f kiau\u0161ini\u0173 baltymus.\n"},1185,[]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"Japoni\u0161ko stiliaus ry\u017eiai keptuv\u0117je\"\nslug: japanese-style-rice\nauthor: Tomas Ravinskas\npublished: 2020-08-01T06:48:06+0300\nedited: 2024-07-24T08:31:13+0300\nsource: http://justhungry.com/how-cook-perfect-rice-in-frying-pan-fast-and-foolproof\n---\n\nJaponi\u0161ko stiliaus vidutinio gr\u016bdo balt\u0173 ry\u017ei\u0173 (plikyti vidutinio gr\u016bdo balti ry\u017eiai irgi tinka) (pla\u010diau [Looking at rice](http://www.justhungry.com/2007/01/looking_at_rice.html))\nTeflonin\u0117s keptuv\u0117s. Naudojau 28cm / 11 coli\u0173 skersmens model\u012f. Rekomenduoju pana\u0161\u0173 dydi 1 - 2 stiklin\u0117ms ry\u017ei\u0173.\nSandaraus dang\u010dio. Tur\u0117t\u0173 b\u016bti tikrai sandarus, kad garai \"nepab\u0117gt\u0173\". Stiklinis ypa\u010d gerai, nes leid\u017eia steb\u0117ti ry\u017eius neatidengiant.\nKelis kartus perplaukite ry\u017eius (metodas ([Japanese rice basics](http://justhungry.com/2003/11/japanese_basics_1.html)) (plovimas tikrai sukuria did\u017eiul\u012f skirtum\u0105, tiesiog tai reikia pakartoti kelis kartus).\nSuberkite nusausintus ry\u017eius \u012f keptuv\u0119 ir \u012fpilkite 1.1 karto daugiau vandens pagal t\u016br\u012f. Taigi jei verdate 1 stiklin\u0119 ry\u017ei\u0173, reik\u0117s 1 stiklin\u0117s ir dar \u0161lakelio vandens.\nJei 2 stiklines, 2 stiklini\u0173 ir 1/4 stiklin\u0117s vandens.\nTokio dyd\u017eio keptuv\u0117je nerekomenduoju virti daugiau kaip 2 stiklini\u0173 ry\u017ei\u0173.\n\nIdealiai dabar paliktume ry\u017eius mirkti (ma\u017edaug 30min), kad tur\u0117tume putlesnius gr\u016bdelius, bet jei skubate -- galite praleisti \u0161\u012f \u017eingsn\u012f.\n\nD\u0117kite u\u017edengt\u0105 keptuv\u0119 ant virykl\u0117s, nustatykite auk\u0161\u010diausia temperat\u016bra. Leiskite u\u017evirti, susidarys daugyb\u0117 krakmolo burbul\u0173.\n\nPermai\u0161ykite ry\u017eius su medine mentele.\n\nV\u0117l u\u017edenkite ir suma\u017einkite temperat\u016bra iki \u017eemos.\n\nJei naudojate elektrine virykl\u0119, temperat\u016bra taip greit nenukris. Tuomet nukelkite keptuv\u0119 nuo virykl\u0117s porai minu\u010di\u0173, kol temperat\u016bra nukris iki reikiamos.\n\nLeiskite ry\u017eiams virti \u017eemoje temperat\u016broje. Matysite kaip vanduo greitai susigeria \u012f ry\u017eius ir didelius krakmolo burbulus pavir\u0161iuje. Tai truks apie 5min, taigi toli nenuklyskite. (Kol tai vyksta u\u017esiimu kitais vakarien\u0117s ruo\u0161imo darbais) (A\u0161 tai ne, per 5min nieko nesp\u0117ju).\n\nKai burbul\u0173 beveik nelieka, matysite tolygias skyles likusias ry\u017ei\u0173 pavir\u0161iuje. Kai taip nutiks, v\u0117l atsukite temperat\u016br\u0105 ant auk\u0161to nustatymo minutei ar dviem ir i\u0161junkite. V\u0117lgi, jei virykl\u0117 elektrin\u0117 -- reik\u0117t\u0173 nukelti.\n\nPalikite ry\u017eius u\u017edengtus dar 10min. Tai labai svarbu, nes kitu atveju ry\u017ei\u0173 viduriukai gali likti kiek kietoki. Al dente gerai makaronams, ne ry\u017eiams! (Bent jau ne Japoni\u0161ko stiliaus ry\u017eiams. Kit\u0173 stili\u0173 ry\u017eiams -- taipogi nemanau).\n"},1186,[]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"K\u016b\u010diukai\"\nslug: kuciukai\nauthor: Tomas Ravinskas\npublished: 2020-12-30T20:40:19+0300\nedited: 2024-07-24T09:48:13+0300\n---\n\n| Kiekis       | Ingredientas   |\n| ------------ | -------------- |\n| 500 g        | milt\u0173          |\n| 3            | kiau\u0161ini\u0173      |\n| 250 ml       | pieno          |\n| 30 g         | mieli\u0173         |\n| 100 g        | cukraus        |\n| 1 \u0161auk\u0161telio | druskos        |\n| 2 \u0161auk\u0161t\u0173    | raps\u0173 aliejaus |\n| 50 g         | aguon\u0173         |\n\n---\n\nPa\u0161ildykite pien\u0105 mikrobang\u0117je ant auk\u0161\u010diausio nustatymo 60 sekund\u017ei\u0173, \u012fd\u0117kite arbatin\u012f \u0161auk\u0161tel\u012f cukraus, ir sud\u0117kite mieles. Mai\u0161ykite kol miel\u0117s i\u0161tirps, tada palikite 10 minu\u010di\u0173, kad miel\u0117s aktyvuotusi. Dideliame, negiliame, dubenyje sumai\u0161ykite pien\u0105, likus\u012f cukr\u0173, aliej\u0173, kiau\u0161inius, ir aguonas. Sumai\u0161ykite miltus su druska ir \u012fsijokite \u012f kiau\u0161ini\u0173 mas\u0119. Minkykite, prid\u0117dami milt\u0173 pagal poreik\u012f, kol te\u0161la nelips prie rank\u0173. U\u017edenkite te\u0161l\u0105 dr\u0117gnu medvilniniu audiniu ir leiskite pakilti apie 60 minu\u010di\u0173.\nAtr\u0117\u017ekite gabal\u0105 te\u0161los ir i\u0161ko\u010diokite apie 1 cm storio de\u0161rel\u0119. Pjaustykite \u012f 1 cm gabal\u0117lius. \u012e kepimo skard\u0105 \u012ftieskite kepimo popieri\u0173 ir suberkite gabal\u0117lius. Kepkite i\u0161 abiej\u0173 pusi\u0173 kol pagels.\n"},1187,[]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"Morengai\"\nslug: meringues\nauthor: Tomas Ravinskas\npublished: 2020-08-01T07:59:03+0300\nedited: 2024-07-24T08:35:13+0300\nsource: \"Sena recept\u0173 knyga, kuri\u0105 mano sesuo rado Vokietijoje\"\n---\n\n| Kiekis   | Ingredientas               |\n| -------- | -------------------------- |\n| 1        | didelio kiau\u0161inio baltymas |\n| 80 g     | baltojo cukraus            |\n| \u0160lakelis | citrinos sul\u010di\u0173            |\n\n---\n\nI\u0161plakite kiau\u0161inio baltym\u0105 su cukrumi ir citrinos sultimis kol prad\u0117s formuotis mink\u0161tos vir\u0161\u016bn\u0117l\u0117s (stand\u017eios vir\u0161\u016bn\u0117s niekada nesusiformuos d\u0117l didelio kiekio cukraus). Semkite mas\u0119 su arbatiniu \u0161auk\u0161teliu ir dr\u0117bkite and kepimo popieriumi padengtos skardos (arba pripildykite konditerin\u012f \u0161virk\u0161t\u0105 ir formuokite gra\u017eius bok\u0161telius). Kepkite 25 minutes 180\xb0C kar\u0161tyje.\n\nViena porcija u\u017epildo ma\u017edaug pus\u0119 orkait\u0117s dyd\u017eio skardos.\n"},1188,[]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"Piro\u017ekos (Pyrag\u0117liai su M\u0117sa)\"\nslug: pirozhki\nauthor: Tomas Ravinskas\npublished: 2020-08-01T10:17:37+0300\nedited: 2024-07-24T09:09:13+0300\n---\n\n### Te\u0161lai\n\n| Kiekis       | Ingredientas      |\n| ------------ | ----------------- |\n| 100 ml       | pieno             |\n| 30 g         | mieli\u0173            |\n| 1 \u0161auk\u0161telio | cukraus           |\n| 3            | dideli\u0173 kiau\u0161ini\u0173 |\n| 500 g        | milt\u0173             |\n| 1 \u0161auk\u0161telio | druskos           |\n\n### \u012edarui\n\n| Kiekis    | Ingredientas                      |\n| --------- | --------------------------------- |\n| 500 g     | m\u0117sos (vi\u0161tienos arba kiaulienos) |\n| 200 g     | tarkuoto kietojo s\u016brio            |\n| 1 kubelio | gryb\u0173 buljono                     |\n\n---\n\nD\u0117kite pien\u0105 \u012f mikrobang\u0119 ir \u0161ildykite ant auk\u0161\u010diausio nustatymo 60 sekund\u017ei\u0173. Suberkite cukr\u0173 ir mieles \u012f \u0161ilt\u0105 pien\u0105 mai\u0161ykite kol miel\u0117s i\u0161tirps (cukrus padeda miel\u0117ms aktyvuotis, te\u0161loje saldumo nesijaus). Palikite pien\u0105 10 minu\u010di\u0173, kol miel\u0117s aktyvuosis. Dideliame, negiliame, dubenyje sumai\u0161ykite pien\u0105 ir kiau\u0161inius. Sumai\u0161ykite miltus su druska ir \u012fsijokite \u012f pieno ir kiau\u0161ini\u0173 mas\u0119. Minkykite kol te\u0161la nebelips prie rank\u0173. U\u017edenkite te\u0161l\u0105 su dr\u0117gnu medvilniniu audiniu ir palikite pakilti, apie 60 minu\u010di\u0173.\n\nKol te\u0161la kyla paruo\u0161kite \u012fdar\u0105. D\u0117kite m\u0117s\u0105 \u012f \u0161alt\u0105 vanden\u012f ir u\u017evirkite. Nuko\u0161kite m\u0117s\u0105, u\u017epilkite \u0161variu vandeniu, ir suberkite buljon\u0105. Virkite 30 minu\u010di\u0173 arba kol m\u0117sa i\u0161virs. Leiskite m\u0117sai atv\u0117sti, tada sumalkite ir suberkite s\u016br\u012f. \u012epilkite kelis \u0161auk\u0161tus buljono, kol pasidarys tir\u0161ta pasta.\n\nAtr\u0117\u017ekite gabal\u0105 te\u0161los ir plonai i\u0161ko\u010diokite. Naudodami stiklin\u0119, i\u0161 te\u0161los spauskite apskritimus. D\u0117kite \u0161auk\u0161tel\u012f pastos \u012f apskritimo vidur\u012f, lenkite per pus\u0119, ir u\u017elankstykite kra\u0161telius. Taip ir toliau kol neliks te\u0161los ir \u012fdaro.\n\n\u012e keptuv\u0119 \u012fpilkite 1 l raps\u0173 ar pana\u0161aus aliejaus ir \u012fkaitinkite ant vidutin\u0117s liepsnos. Kai aliejus \u012fkaista, d\u0117kite kelis pyrag\u0117lius \u012f keptuv\u0119 ir virkite kol pagels. Kai viena pus\u0117 pagelto, apverskite, ir v\u0117l virkite kol pagels kita pus\u0117.\n\n\u012etieskite \u012f didel\u012f duben\u012f por\u0105 popierini\u0173 rank\u0161luos\u010di\u0173 ir \u017evejokite piro\u017ekas. Popieriniai rank\u0161luos\u010diai sugers aliejaus pertekli\u0173, kad piro\u017ekos i\u0161likt\u0173 tra\u0161kios.\n"},1189,[]);
__d(function(g,r,i,a,m,e,d){m.exports="---\ntitle: \"Tinginys\"\nslug: tinginys\nauthor: Tomas Ravinskas\npublished: 2020-08-01T07:59:23+0300\nedited: 2024-07-24T07:53:13+0300\n---\n\n| Kiekis              | Ingredientas                              |\n| ------------------- | ----------------------------------------- |\n| 900 g               | sausaini\u0173 (a\u0161 naudoju Selga arba Leibniz) |\n| 1 skardin\u0117s (400 g) | saldinto kondensuoto pieno                |\n| 200 g               | sviesto                                   |\n| 250 g               | margarino kepiniams                       |\n| 3 \u0161auk\u0161t\u0173           | cukraus                                   |\n| 5 \u0161auk\u0161t\u0173           | kakavos                                   |\n\n---\n\nSutrupinkite sausainius \u012f ma\u017edaug 1 cm dyd\u017eio gabal\u0117lius. I\u0161tirpinkite sviest\u0105 ir margarin\u0105 vir\u0161 \u017eemos liepsnos. \u012emai\u0161ykite cukr\u0173, pastoviai mai\u0161ydami kol cukrus i\u0161tirps. Toliau mai\u0161ydami supilkite kondensuot\u0105 pien\u0105. Mai\u0161ykite iki vientisos mas\u0117s. I\u0161junkite liepsn\u0105 ir leiskite prav\u0117sti, ma\u017edaug 10-15 minu\u010di\u0173.\n\n\u012emai\u0161ykite kakav\u0105 ir supilkite mas\u0119 ant sausaini\u0173 trupini\u0173. Gerai i\u0161mai\u0161ykite, ir supilkite sausaini\u0173 mas\u0119 \u012f gili\u0105, siaur\u0105, kepimo form\u0105.\nD\u0117kite \u012f \u0161aldytuv\u0105 nak\u010diai.\n\n---\n\n\u017dinau, kad daug kam nepatinka margarinas, ta\u010diau \u010dia jis puikiai tinka.\nGalite gaminti vien su sviestu (pakeisdami margarin\u0105 tokiu pa\u010diu kiekiu sviesto), ta\u010diau galinis rezultatas bus daug kietesnis.\n"},1190,[]);
